ValidationRule.errorConditionFormula:
AND(
OR( ISCHANGED ( Status__c ), ISCHANGED ( Resolution_Date__c ),
AND( ISNEW(), OR( NOT(ISPICKVAL(Status__c ,'Submitted')), NOT(ISBLANK(Resolution_Date__c)) ) )
),
NOT(CONTAINS($User.Username, 'liord@similarweb.com')), NOT(CONTAINS($User.Username, 'daniel.gelbshtein@similarweb.com')), NOT(CONTAINS($User.Username, 'laura.or@similarweb.com')), NOT(CONTAINS($User.Username, 'inbal.spiegel@similarweb.com')), $Profile.Name != 'System Administrator', RecordType.DeveloperName = 'Churn_Protection'
)
